This example uses a fixed size for simplicity.

```c
#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 100

int main() {
    int data[MAX_SIZE];
    int n;

    // 1. Get the number of elements the user wants to enter
    printf("Enter the number of elements (max %d): ", MAX_SIZE);
    if (scanf("%d", &n) != 1 || n <= 0 || n > MAX_SIZE) {
        printf("Invalid number entered. Exiting.\n");
        return 1;
    }

    // 2. Get the data from the user
    printf("\nEnter %d integer values:\n", n);
    for (int i = 0; i < n; i++) {
        printf("Enter element %d: ", i + 1);
        if (scanf("%d", &data[i]) != 1) {
            printf("Invalid input. Exiting.\n");
            return 1;
        }
    }

    // 3. Generate and display the sequential table
    printf("\n======================================\n");
    printf("       SEQUENTIAL DATA TABLE\n");
    printf("======================================\n");

    for (int i = 0; i < n; i++) {
        // Displaying the row number (index + 1) and the data
        printf("Row %d: %d\n", i + 1, data[i]);
    }

    printf("======================================\n");

    return 0;
}
```

### Explanation:

1.  **`#define MAX_SIZE 100`**: Sets a maximum limit for the data size.
2.  **Input Size (`n`)**: The program first asks the user how many numbers they intend to enter.
3.  **Data Input Loop**: A `for` loop iterates `n` times, prompting the user to enter each piece of data and storing it in the `data` array.

